import{tokenisePath}from"./treeUtil";import{inspect}from"util";export const doesLookupMatch=(lookup,symbolPath)=>{const lookupPath=Array.isArray(lookup)?lookup:tokenisePath(lookup);const lastIdx=lookupPath.length;let lookupIdx=0;let symbolIdx=0;while(symbolIdx<lastIdx){if(symbolIdx>=symbolPath.length)return false;const currentSymbol=symbolPath[symbolIdx];const currentToken=lookupPath[lookupIdx];if([currentSymbol,"*"].includes(currentToken)){symbolIdx++;lookupIdx++}else if(currentToken==="**"){if(lookupIdx===lastIdx)break;lookupIdx++;return doesLookupMatch(lookupPath.slice(lookupIdx).reverse(),symbolPath.slice(symbolIdx).reverse())}else if(currentToken.endsWith("*")&&currentSymbol.startsWith(currentToken.slice(0,currentToken.indexOf("*")))){symbolIdx++;lookupIdx++}else{return false}}return true};export function valueTransform(path,value,valueTransformers){const symbolPath=tokenisePath(path);for(const[lookup,transformer]of Object.entries(valueTransformers)){if(doesLookupMatch(lookup,symbolPath)){const old=value;value=transformer(value,symbolPath);if(old!==value){try{logger.trace({key:symbolPath.join("."),transformer:lookup,oldValue:old instanceof Buffer?inspect(old):old,newValue:value},"Value transformed")}catch(e){logger.warn({key:symbolPath.join("."),transformer:lookup,error:e.toString()},"Value transformed, but could not serialise values")}}break}}return value}export const DEFAULT_TRANSFORMS={integer:{boolean(value){if(value===1){return true}else if(value===0){return false}throw new Error("Unexpected value converting "+value)}},buffer:{boolean(bytes){if(bytes.equals(new Uint8Array([0,0,128,63]))){return true}else if(bytes.equals(new Uint8Array([0,0,0,0]))){return false}throw new Error("Unexpected value converting "+bytes)},float(bytes){return bytes.readFloatLE()}}};export const IGNORE=Symbol("Ignore");